// Flatten the incoming payload for Airtable
const body = $input.first().json.body || $input.first().json;

const student = body.studentProfile || {};
const programs = body.selectedPrograms || [];
const docs = body.uploadedDocs || {};

// Format selected programs as readable list
const programList = programs.map(p =>
  `${p.Program_Name} — ${p.University} (${p.City}, ${p.Province})`
).join('\n');

// Format doc URLs
const docLinks = Object.entries(docs).map(([type, files]) => {
  if (Array.isArray(files)) {
    return files.map(f => `${type}: ${f.url}`).join('\n');
  }
  return `${type}: ${files.url || files}`;
}).join('\n');

return [{
  json: {
    // Student info
    full_name: student.firstName + ' ' + student.lastName,
    first_name: student.firstName,
    last_name: student.lastName,
    email: student.email,
    phone: student.phone,
    gpa: student.gpa,
    test_type: student.testType,
    ielts_equivalent: student.ieltsEquiv,
    nationality: student.nationality,
    dob: student.dob,
    degree_level: student.degreeLevel,
    field_of_study: student.fieldOfStudy,
    institution: student.institution,
    grad_year: student.gradYear,
    work_experience: student.workExp,
    notes: student.notes || '',
    // Programs
    programs_selected: programs.length,
    program_list: programList,
    // Documents
    doc_links: docLinks,
    docs_submitted: Object.keys(docs).join(', '),
    // Meta
    submitted_at: body.submittedAt,
    source: body.source || 'apply.adsimmigration.com',
    // Raw JSON for reference
    raw_payload: JSON.stringify(body)
  }
}];
